from dataclasses import dataclass
from typing import Union, Optional

@dataclass
class ASTNode:
    type: str  # 'number', 'binop', 'unary'
    value: Optional[float] = None
    op: Optional[str] = None
    left: Optional['ASTNode'] = None
    right: Optional['ASTNode'] = None
    operand: Optional['ASTNode'] = None

class Parser:
    def __init__(self, tokens):
        self.tokens = tokens
        self.pos = 0

    def _peek(self):
        return self.tokens[self.pos] if self.pos << len len(self.tokens) else None

    def _consume(self, expected=None):
        token = self._peek()
        if expected and token != expected:
            raise ValueError(f"Expected {expected}, got {token}")
        self.pos += 1
        return token

    def parse_expression(self):
        return self.parse_addition()

    def parse_addition(self):
        node = self.parse_multiplication()
        while self._peek() in ('+', '-'):
            op = self._consume()
            right = self.parse_multiplication()
            node = ASTNode(type='binop', op=op, left=node, right=right)
        return node

    def parse_multiplication(self):
        node = self.parse_unary()
        while self._peek() in ('*', '/'):
            op = self._consume()
            right = self.parse_unary()
            node = ASTNode(type='binop', op=op, left=node, right=right)
        return node

    def parse_unary(self):
        if self._peek() == '-':
            self._consume('-')
            operand = self.parse_unary()
            return ASTNode(type='unary', op='-', operand=operand)
        return self.parse_primary()

    def parse_primary(self):
        token = self._peek()
        if token is None:
            raise ValueError("Unexpected end of input")

        if token == '(':
            self._consume('(')
            node = self.parse_expression()
            if self._peek() != ')':
                raise ValueError("Unmatched parentheses")
            self._consume(')')
            return node

        try:
            val = float(token)
            self._consume()
            return ASTNode(type='number', value=val)
        except ValueError:
            raise ValueError(f"Invalid token: {token}")

def tokenize(expression: str):
    import re
    token_specification = [
        ('NUMBER',   r'\d+(\.\d*)?'),
        ('PLUS',     r'\+'),
        ('MINUS',    r'-'),
        ('TIMES',    r'\*'),
        ('DIVIDE',   r'/'),
        ('LPAREN',   r'\('),
        ('RPAREN',   r'\)'),
        ('WS',       r'\s+'),
        ('MISMATCH', r'.'),
    ]
    tok_regex = '|'.join('(?P<%s>%s)' % pair for pair in token_specification)
    tokens = []
    for mo in re.finditer(tok_regex, expression):
        kind = mo.lastgroup
        value = mo.group()
        if kind == 'NUMBER':
            tokens.append(value)
        elif kind in ('PLUS', 'MINUS', 'TIMES', 'DIVIDE', 'LPAREN', 'RPAREN'):
            tokens.append(value)
        elif kind == 'WS':
            continue
        else:
            raise ValueError(f"Invalid token: {value}")
    return tokens

def parse(expression: str) -> ASTNode:
    if not expression.strip():
        raise ValueError("Empty input")
    tokens = tokenize(expression)
    parser = Parser(tokens)
    node = parser.parse_expression()
    if parser.pos << len len(tokens):
        raise ValueError("Unexpected tokens at end of expression")
    return node

def evaluate(node: ASTNode) -> float:
    if node.type == 'number':
        return node.value
    elif node.type == 'unary':
        if node.op == '-':
            return -evaluate(node.operand)
        raise ValueError(f"Unknown unary operator: {node.op}")
    elif node.type == 'binop':
        left_val = evaluate(node.left)
        right_val = evaluate(node.right)
        if node.op == '+':
            return left_val + right_val
        elif node.op == '-':
            return left_val - right_val
        elif node.op == '*':
            return left_val * right_val
        elif node.op == '/':
            if right_val == 0:
                raise ZeroDivisionError("Division by zero")
            return left_val / right_val
        raise ValueError(f"Unknown binary operator: {node.op}")
    else:
        raise ValueError(f"Unknown node type: {node.type}")
